# Policy assignments at MG, subscription, and resource group scope

# MG scope — initiative assignment with managed identity
resource "azurerm_management_group_policy_assignment" "corp_baseline" {
  name                 = "corp-baseline"
  management_group_id  = data.azurerm_management_group.corp.id
  policy_definition_id = azurerm_policy_set_definition.corp_baseline.id
  location             = "eastus"
  enforce              = true

  parameters = jsonencode({
    tagName               = { value = "environment" }
    listOfAllowedLocations = { value = ["eastus", "eastus2", "westeurope"] }
  })

  non_compliance_message {
    content = "Resources must comply with Corp baseline policy. Contact platform@example.com."
  }

  identity {
    type = "SystemAssigned"
  }
}

# Grant the assignment identity Contributor at Corp MG
resource "azurerm_role_assignment" "baseline_identity" {
  scope                = data.azurerm_management_group.corp.id
  role_definition_name = "Contributor"
  principal_id         = azurerm_management_group_policy_assignment.corp_baseline.identity[0].principal_id
}

# Subscription scope — override region list for APAC sub
resource "azurerm_subscription_policy_assignment" "apac_regions" {
  name                 = "apac-allowed-regions"
  subscription_id      = var.apac_subscription_id
  policy_definition_id = data.azurerm_policy_definition.allowed_locations.id
  enforce              = true

  parameters = jsonencode({
    listOfAllowedLocations = { value = ["australiaeast", "southeastasia"] }
  })
}

# Resource group scope — workload-specific rule
resource "azurerm_resource_group_policy_assignment" "payments_sku" {
  name                 = "payments-vm-skus"
  resource_group_id    = data.azurerm_resource_group.payments.id
  policy_definition_id = data.azurerm_policy_definition.allowed_vm_skus.id

  parameters = jsonencode({
    listOfAllowedSKUs = { value = ["Standard_D2s_v5", "Standard_D4s_v5"] }
  })
}

# policy-assignments.tf — assignments at all four scope levels

# ── Management Group Scope ─────────────────────────────────────────────
# Assign the built-in 'Require a tag on resources' initiative to the Corp MG
resource "azurerm_management_group_policy_assignment" "corp_tagging_initiative" {
  name                 = "corp-tagging-initiative"
  display_name         = "Corp Tagging Standards"
  policy_definition_id = "/providers/Microsoft.Authorization/policySetDefinitions/1f3afdf9-d0c9-4c3d-847f-89da613e70a8"
  management_group_id  = var.corp_mg_id

  parameters = jsonencode({
    tagName = { value = "cost-center" }
  })
}

# ── Subscription Scope ─────────────────────────────────────────────────
# Deny VMs without approved SKUs; DoNotEnforce on dev, Deny on prod
resource "azurerm_subscription_policy_assignment" "allowed_vm_skus" {
  for_each = var.subscription_ids

  name                 = "allowed-vm-skus"
  display_name         = "Allowed VM SKUs"
  policy_definition_id = data.azurerm_policy_definition.allowed_vm_skus.id
  subscription_id      = "/subscriptions/${each.value}"

  # Enforce on prod, audit-only on dev/test
  enforce = each.key == "prod" ? true : false

  parameters = jsonencode({
    listOfAllowedSKUs = { value = [
      "Standard_D2s_v3", "Standard_D4s_v3",
      "Standard_D8s_v3", "Standard_E2s_v3"
    ]}
  })
}

data "azurerm_policy_definition" "allowed_vm_skus" {
  display_name = "Allowed virtual machine size SKUs"
}

# ── Resource Group Scope ───────────────────────────────────────────────
# Append a created-by tag to all resources in legacy resource groups
resource "azurerm_resource_group_policy_assignment" "legacy_rg_tagging" {
  for_each = toset(var.legacy_resource_groups)

  name                 = "legacy-tagging-${each.key}"
  display_name         = "Legacy RG Tagging: ${each.key}"
  policy_definition_id = azurerm_policy_definition.append_env_tag.id
  resource_group_id    = "/subscriptions/${var.prod_sub_id}/resourceGroups/${each.key}"

  not_scopes = [
    # Exempt the read-only export container
    "/subscriptions/${var.prod_sub_id}/resourceGroups/${each.key}/providers/Microsoft.Storage/storageAccounts/sa-exports"
  ]
}

# ── Resource Scope ─────────────────────────────────────────────────────
# Target a single critical Key Vault with an audit-level private endpoint check
resource "azurerm_resource_policy_assignment" "kv_private_endpoint_audit" {
  name                 = "kv-private-endpoint-check"
  display_name         = "Key Vault: require private endpoint"
  policy_definition_id = "/providers/Microsoft.Authorization/policyDefinitions/a6fb4358-5bf4-4ad7-ba82-2cd2f41ce5e9"
  resource_id          = var.critical_keyvault_id
  enforce              = false  # audit, alert, do not block
}

# DINE assignment with system-assigned managed identity
# Required for DeployIfNotExists and Modify effects
resource "azurerm_subscription_policy_assignment" "deploy_law_agent" {
  name                 = "deploy-law-agent"
  display_name         = "Deploy Log Analytics agent to Windows VMs"
  policy_definition_id = azurerm_policy_definition.deploy_law_windows.id
  subscription_id      = "/subscriptions/${var.prod_sub_id}"

  identity {
    type = "SystemAssigned"
  }

  # Location is required when identity block is present
  location = var.primary_location

  parameters = jsonencode({
    logAnalyticsWorkspaceId = { value = var.log_analytics_workspace_id }
  })
}

# Grant the policy managed identity the Contributor role it needs
# (The policy definition's roleDefinitionIds specifies which role)
resource "azurerm_role_assignment" "policy_mi_contributor" {
  scope                = "/subscriptions/${var.prod_sub_id}"
  role_definition_name = "Contributor"
  principal_id         = azurerm_subscription_policy_assignment.deploy_law_agent.identity[0].principal_id

  depends_on = [azurerm_subscription_policy_assignment.deploy_law_agent]
}
